        server_context.localInfo(),                       // Local node info
        server_context.clusterManager(),                  // Cluster manager for routing
        overload_manager,                                 // Overload manager for pressure relief
        server_context.mainThreadDispatcher().timeSource(), // Time source
        context.listenerInfo().direction()                // Downstream/Upstream
