void ConnectionManagerImpl::createCodec(Buffer::Instance& data) {
  ASSERT(!codec_);

  // Delegate to config to create appropriate codec (H1, H2, H3)
  codec_ = config_->createCodec(
      read_callbacks_->connection(),  // Network connection
      data,                            // First bytes to analyze
      *this,                           // ServerConnectionCallbacks
      overload_manager_);              // For load shedding

  // Record codec statistics
  switch (codec_->protocol()) {
  case Protocol::Http3:
    stats_.named_.downstream_cx_http3_total_.inc();
    stats_.named_.downstream_cx_http3_active_.inc();
    break;
  case Protocol::Http2:
    stats_.named_.downstream_cx_http2_total_.inc();
    stats_.named_.downstream_cx_http2_active_.inc();
    break;
  case Protocol::Http11:
  case Protocol::Http10:
    stats_.named_.downstream_cx_http1_total_.inc();
    stats_.named_.downstream_cx_http1_active_.inc();
    break;
  }
}
